 82→export async function POST(request: NextRequest) {
 83→  try {
 84→    const userId = await getAuthenticatedUserId();
 85→    const body = await request.json();
 86→    const { transactions, origin } = body;
 87→
 88→    if (!transactions || !Array.isArray(transactions)) {
 89→      return NextResponse.json(
 90→        { error: "Transacoes invalidas" },
 91→        { status: 400 }
 92→      );
 93→    }
 94→
 95→    // Fetch ALL active recurring expenses for matching (not just autoGenerate=false)
 96→    const recurringToMatch = await prisma.recurringExpense.findMany({
 97→      where: {
 98→        userId,
 99→        isActive: true,
100→      },
101→      include: {
102→        transactions: {
103→          select: { id: true, date: true },
104→          where: { deletedAt: null },
105→        },
106→      },
107→    });
108→
109→    // Fetch user's category tags for validation
110→    const userTagIds = new Set(
111→      (await prisma.categoryTag.findMany({
112→        where: { userId },
113→        select: { id: true, categoryId: true },
114→      })).map(t => `${t.id}:${t.categoryId}`)
115→    );
116→
117→    // Generate a batch ID for this import
118→    const importBatchId = crypto.randomUUID();
119→
120→    const created = [];
121→    let linkedCount = 0;
122→    let carryoverLinkedCount = 0;
123→    const linkedCarryovers: Array<{
124→      transactionId: string;
125→      billPaymentId: string;
126→      fromBill: string;
127→      interestRate: number | null;
128→      interestAmount: number | null;
129→    }> = [];
130→
131→    for (const t of transactions) {
132→      // Determine type and amount sign
133→      const type = t.type || "EXPENSE";
134→      let amount = t.amount;
135→
136→      // Ensure amount sign matches type
137→      if (type === "EXPENSE" && amount > 0) {
138→        amount = -amount;
139→      } else if (type === "INCOME" && amount < 0) {
140→        amount = Math.abs(amount);
141→      }
142→
143→      // Parse date safely to avoid timezone issues with YYYY-MM-DD format
144→      const dateStr = typeof t.date === 'string' && !t.date.includes('T')
145→        ? t.date + 'T12:00:00'
146→        : t.date;
147→      const transactionDate = new Date(dateStr);
148→      const transactionMonth = transactionDate.getMonth();
149→      const transactionYear = transactionDate.getFullYear();
150→      const transactionOrigin = origin || t.origin || "Importacao CSV";
151→
152→      // Try to match with a recurring expense
153→      let matchedRecurringId: string | null = null;
154→
155→      // Validate frontend-provided recurringExpenseId belongs to this user
156→      if (t.recurringExpenseId) {
157→        const isOwned = recurringToMatch.some(r => r.id === t.recurringExpenseId);
158→        if (isOwned) {
159→          matchedRecurringId = t.recurringExpenseId;
160→        }
161→      }
162→
163→      // Only do server-side matching if no valid match from frontend
164→      if (!matchedRecurringId) {
165→        const matches = recurringToMatch.filter((recurring) => {
166→          // Check origin match
167→          if (recurring.origin !== transactionOrigin) {
168→            return false;
169→          }
170→
171→          // Check category match (if recurring has category defined)
172→          if (recurring.categoryId && t.categoryId && recurring.categoryId !== t.categoryId) {
173→            return false;
174→          }
175→
176→          // Check description match
177→          if (!matchesRecurring(t.description, recurring.description)) {
178→            return false;
179→          }
180→
181→          // Check if already has transaction for this month
182→          const hasThisMonth = recurring.transactions.some((existingTx) => {
183→            const existingDate = new Date(existingTx.date);
184→            return (
185→              existingDate.getMonth() === transactionMonth &&
186→              existingDate.getFullYear() === transactionYear
187→            );
188→          });
189→
190→          if (hasThisMonth) {
191→            return false;
192→          }
193→
194→          return true;
195→        });
196→
197→        // Only link if we have exactly one match (conservative)
198→        if (matches.length === 1) {
199→          matchedRecurringId = matches[0].id;
200→          // Add to existing transactions to prevent double matching in same import
201→          matches[0].transactions.push({ id: "temp", date: transactionDate });
202→          linkedCount++;
203→        }
204→      } else {
205→        linkedCount++;
206→      }
207→
208→      // Validate frontend-provided categoryTagId belongs to user and matches category
209→      let validatedTagId: string | null = null;
210→      if (t.categoryTagId) {
211→        const tagKey = `${t.categoryTagId}:${t.categoryId || ""}`;
212→        if (userTagIds.has(tagKey)) {
213→          validatedTagId = t.categoryTagId;
214→        }
215→      }
216→
217→      const transaction = await prisma.transaction.create({
218→        data: {
219→          userId,
220→          description: t.description,
221→          amount,
222→          date: transactionDate,
223→          type,
224→          origin: transactionOrigin,
225→          categoryId: t.categoryId || null,
226→          categoryTagId: validatedTagId,
227→          isFixed: matchedRecurringId !== null,
228→          isInstallment: t.isInstallment || false,
229→          currentInstallment: t.currentInstallment || null,
230→          totalInstallments: t.totalInstallments || null,
231→          recurringExpenseId: matchedRecurringId,
232→          importBatchId,
233→        },
234→        include: {
235→          category: true,
236→          recurringExpense: true,
237→        },
238→      });
239→      created.push(transaction);
240→
241→      // Check if this is a carryover transaction and try to link it to a BillPayment
242→      if (isCarryoverTransaction(t.description)) {
243→        try {
244→          const matchingBillPayment = await findMatchingBillPayment({
245→            origin: transactionOrigin,
246→            month: transactionMonth + 1, // Convert from 0-indexed to 1-indexed
247→            year: transactionYear,
248→            amount: Math.abs(amount),
249→            userId,
250→          });
251→
252→          if (matchingBillPayment) {
253→            // Calculate interest from the difference
254→            const interest = calculateInterest(
255→              matchingBillPayment.amountCarried,
256→              Math.abs(amount)
257→            );
258→
259→            // Update the BillPayment with the linked transaction and interest info
260→            await prisma.billPayment.update({
261→              where: { id: matchingBillPayment.id },
262→              data: {
263→                linkedTransactionId: transaction.id,
264→                interestRate: interest.rate,
265→                interestAmount: interest.amount,
266→              },
267→            });
268→
269→            // Soft delete the old carryover transaction if it exists
270→            if (matchingBillPayment.carryoverTransactionId) {
271→              await prisma.transaction.update({
272→                where: { id: matchingBillPayment.carryoverTransactionId },
273→                data: { deletedAt: new Date() },
274→              });
275→            }
276→
277→            carryoverLinkedCount++;
278→            linkedCarryovers.push({
279→              transactionId: transaction.id,
280→              billPaymentId: matchingBillPayment.id,
281→              fromBill: `${matchingBillPayment.billMonth}/${matchingBillPayment.billYear}`,
282→              interestRate: interest.rate,
283→              interestAmount: interest.amount,
284→            });
285→          }
286→        } catch (carryoverError) {
287→          // Log but don't fail the import if carryover linking fails
288→          console.error("Error linking carryover transaction:", carryoverError);
289→        }
290→      }
291→    }
292→
293→    // Build response message
294→    const messageParts = [`${created.length} transacoes importadas`];
295→    if (linkedCount > 0) {
296→      messageParts.push(`${linkedCount} vinculadas a recorrentes`);
297→    }
298→    if (carryoverLinkedCount > 0) {
299→      messageParts.push(`${carryoverLinkedCount} vinculadas a saldo rolado`);
300→    }
301→    const message =
302→      linkedCount > 0 || carryoverLinkedCount > 0
303→        ? `${messageParts[0]} (${messageParts.slice(1).join(", ")})`
304→        : `${created.length} transacoes importadas com sucesso`;
305→
306→    return NextResponse.json(
307→      {
308→        message,
309→        count: created.length,
310→        linkedCount,
311→        carryoverLinkedCount,
312→        linkedCarryovers,
313→        importBatchId,
314→      },
315→      { status: 201 }
316→    );
317→  } catch (error) {
318→    if (error instanceof Error && error.message === "Unauthorized") {
319→      return unauthorizedResponse();
320→    }
321→    console.error("Error importing transactions:", error);
322→    return NextResponse.json(
323→      { error: "Erro ao importar transacoes" },
324→      { status: 500 }
325→    );
326→  }
327→}
