const TELEGRAM_API = `https://api.telegram.org/bot${process.env.TELEGRAM_BOT_TOKEN}`

export interface TelegramUpdate {
  update_id: number
  message?: TelegramMessage
  callback_query?: TelegramCallbackQuery
}

export interface TelegramMessage {
  message_id: number
  from?: { id: number; first_name: string }
  chat: { id: number; type: string }
  date: number
  text?: string
  document?: TelegramDocument
}

export interface TelegramCallbackQuery {
  id: string
  from: { id: number; first_name: string }
  message?: TelegramMessage
  data?: string
}

export interface TelegramDocument {
  file_id: string
  file_name?: string
  mime_type?: string
  file_size?: number
}

export interface InlineKeyboardButton {
  text: string
  callback_data: string
}

export async function sendMessage(
  chatId: number | string,
  text: string,
  options?: {
    reply_markup?: {
      inline_keyboard: InlineKeyboardButton[][]
    }
    parse_mode?: "HTML" | "Markdown" | "MarkdownV2"
  }
) {
  const res = await fetch(`${TELEGRAM_API}/sendMessage`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      chat_id: chatId,
      text,
      ...options,
    }),
  })
  return res.json()
}

export async function answerCallbackQuery(
  callbackQueryId: string,
  text?: string
) {
  const res = await fetch(`${TELEGRAM_API}/answerCallbackQuery`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      callback_query_id: callbackQueryId,
      text,
    }),
  })
  return res.json()
}

export async function editMessageText(
  chatId: number | string,
  messageId: number,
  text: string,
  options?: {
    reply_markup?: {
      inline_keyboard: InlineKeyboardButton[][]
    }
    parse_mode?: "HTML" | "Markdown" | "MarkdownV2"
  }
) {
  const res = await fetch(`${TELEGRAM_API}/editMessageText`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      chat_id: chatId,
      message_id: messageId,
      text,
      ...options,
    }),
  })
  return res.json()
}

export async function getFile(fileId: string) {
  const res = await fetch(`${TELEGRAM_API}/getFile`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ file_id: fileId }),
  })
  const data = await res.json()
  return data.result?.file_path as string | undefined
}

export async function downloadFile(filePath: string): Promise<string> {
  const url = `https://api.telegram.org/file/bot${process.env.TELEGRAM_BOT_TOKEN}/${filePath}`
  const res = await fetch(url)
  return res.text()
}

export async function setWebhook(url: string, secretToken: string) {
  const res = await fetch(`${TELEGRAM_API}/setWebhook`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      url,
      secret_token: secretToken,
      allowed_updates: ["message", "callback_query"],
    }),
  })
  return res.json()
}

import type { NextAuthConfig } from "next-auth"

// Edge-compatible config (used by middleware)
// This file should NOT import Prisma or bcrypt (not edge-compatible)
export const authConfig = {
  pages: {
    signIn: "/auth/login",
    error: "/auth/error",
  },
  callbacks: {
    authorized({ auth, request: { nextUrl } }) {
      const isLoggedIn = !!auth?.user
      const isOnAuthPage = nextUrl.pathname.startsWith("/auth")
      const isApiAuthRoute = nextUrl.pathname.startsWith("/api/auth")
      const isLandingPage = nextUrl.pathname === "/"
      const isTelegramWebhook = nextUrl.pathname === "/api/telegram/webhook"

      // Allow landing page, auth pages, auth API routes, and Telegram webhook without authentication
      if (isLandingPage || isOnAuthPage || isApiAuthRoute || isTelegramWebhook) {
        return true
      }

      // Redirect to login if not authenticated
      if (!isLoggedIn) {
        return false
      }

      return true
    },
  },
  providers: [], // Providers are added in auth.ts
} satisfies NextAuthConfig

import prisma from "@/lib/db"
import { formatCurrency } from "@/lib/utils"
import { sendMessage, type InlineKeyboardButton } from "./client"

export async function handleSummaryQuery(chatId: number, userId: string) {
  const now = new Date()
  const month = now.getMonth() + 1
  const year = now.getFullYear()

  const monthStart = new Date(year, month - 1, 1)
  const monthEnd = new Date(year, month, 0, 23, 59, 59, 999)

  // Fetch transactions for current month
  const transactions = await prisma.transaction.findMany({
    where: {
      userId,
      date: { gte: monthStart, lte: monthEnd },
      deletedAt: null,
    },
    include: { investmentTransaction: true },
  })

  // Calculate totals (same logic as /api/summary)
  let income = 0
  let expense = 0
  for (const t of transactions) {
    if ((t as Record<string, unknown>).investmentTransaction) continue
    if (t.type === "TRANSFER") continue
    if (t.type === "INCOME") income += Math.abs(t.amount)
    else if (t.type === "EXPENSE") expense += Math.abs(t.amount)
  }
  const balance = income - expense

  // Get total budget
  const budgets = await prisma.budget.findMany({
    where: { userId, isActive: true },
  })
  const totalBudget = budgets.reduce((sum, b) => sum + b.amount, 0)

  const monthName = monthStart.toLocaleDateString("pt-BR", { month: "long", year: "numeric" })

  const lines = [
    `📊 Resumo - ${monthName}`,
    "",
    `Despesas:  ${formatCurrency(expense)}`,
    `Receitas:  ${formatCurrency(income)}`,
    `Saldo:     ${formatCurrency(balance)}`,
  ]

  if (totalBudget > 0) {
    const pct = Math.round((expense / totalBudget) * 100)
    const filled = Math.round(pct / 10)
    const bar = "█".repeat(Math.min(filled, 10)) + "░".repeat(Math.max(10 - filled, 0))
    lines.push("")
    lines.push(`Orçamento: ${formatCurrency(totalBudget)}`)
    lines.push(`Usado:     ${pct}% ${bar}`)
  }

  return sendMessage(chatId, lines.join("\n"), {
    reply_markup: {
      inline_keyboard: [[{ text: "🔙 Menu", callback_data: "menu:0" }]],
    },
  })
}

export async function handleCategoryQuery(chatId: number, userId: string) {
  const now = new Date()
  const month = now.getMonth() + 1
  const year = now.getFullYear()

  const monthStart = new Date(year, month - 1, 1)
  const monthEnd = new Date(year, month, 0, 23, 59, 59, 999)

  // Fetch expense transactions with categories
  const transactions = await prisma.transaction.findMany({
    where: {
      userId,
      type: "EXPENSE",
      date: { gte: monthStart, lte: monthEnd },
      deletedAt: null,
    },
    include: { category: true },
  })

  // Aggregate by category
  const categoryTotals = new Map<string, { name: string; total: number }>()
  for (const t of transactions) {
    const catName = t.category?.name || "Sem categoria"
    const catId = t.categoryId || "none"
    const existing = categoryTotals.get(catId) || { name: catName, total: 0 }
    existing.total += Math.abs(t.amount)
    categoryTotals.set(catId, existing)
  }

  // Fetch budgets
  const budgets = await prisma.budget.findMany({
    where: { userId, isActive: true },
    include: { category: true },
  })
  const budgetMap = new Map(budgets.map(b => [b.categoryId, b.amount]))

  const monthName = monthStart.toLocaleDateString("pt-BR", { month: "long", year: "numeric" })

  const lines = [`🏷️ Gastos por categoria - ${monthName}`, ""]

  // Sort by total descending
  const sorted = Array.from(categoryTotals.entries()).sort((a, b) => b[1].total - a[1].total)

  for (const [catId, { name, total }] of sorted) {
    const budget = budgetMap.get(catId)
    if (budget) {
      const pct = Math.round((total / budget) * 100)
      const warning = pct >= 100 ? " ⚠️" : ""
      lines.push(`${name}: ${formatCurrency(total)} / ${formatCurrency(budget)} (${pct}%)${warning}`)
    } else {
      lines.push(`${name}: ${formatCurrency(total)}`)
    }
  }

  if (sorted.length === 0) {
    lines.push("Nenhuma despesa neste mês.")
  }

  return sendMessage(chatId, lines.join("\n"), {
    reply_markup: {
      inline_keyboard: [[{ text: "🔙 Menu", callback_data: "menu:0" }]],
    },
  })
}

export async function handleTransactionsQuery(
  chatId: number,
  userId: string,
  offset: number = 0
) {
  const limit = 10
  const transactions = await prisma.transaction.findMany({
    where: {
      userId,
      deletedAt: null,
    },
    include: { category: true },
    orderBy: { date: "desc" },
    skip: offset,
    take: limit + 1, // Fetch one extra to check if there are more
  })

  const hasMore = transactions.length > limit
  const display = transactions.slice(0, limit)

  const lines = [`📋 ${offset === 0 ? "Últimas" : "Mais"} transações`, ""]

  for (const t of display) {
    const date = new Date(t.date).toLocaleDateString("pt-BR", {
      day: "2-digit",
      month: "2-digit",
    })
    const sign = t.type === "INCOME" ? "+" : "-"
    const amount = formatCurrency(Math.abs(t.amount))
    const cat = t.category?.name || ""
    lines.push(`${date} ${t.description.substring(0, 25)}  ${sign}${amount}  ${cat}`)
  }

  if (display.length === 0) {
    lines.push("Nenhuma transação encontrada.")
  }

  const keyboard: InlineKeyboardButton[][] = []
  const navRow: InlineKeyboardButton[] = []
  if (offset > 0) {
    navRow.push({ text: "⬅️ Anteriores", callback_data: `txns:${Math.max(0, offset - limit)}` })
  }
  if (hasMore) {
    navRow.push({ text: "➡️ Próximas", callback_data: `txns:${offset + limit}` })
  }
  if (navRow.length > 0) keyboard.push(navRow)
  keyboard.push([{ text: "🔙 Menu", callback_data: "menu:0" }])

  return sendMessage(chatId, lines.join("\n"), {
    reply_markup: { inline_keyboard: keyboard },
  })
}

import prisma from "@/lib/db"

export interface DuplicateCheckParams {
  userId: string
  description: string
  amount: number
  date: Date
}

export async function findDuplicate({
  userId,
  description,
  amount,
  date,
}: DuplicateCheckParams) {
  // Normalize date to start/end of day
  const dayStart = new Date(date)
  dayStart.setHours(0, 0, 0, 0)
  const dayEnd = new Date(date)
  dayEnd.setHours(23, 59, 59, 999)

  const duplicate = await prisma.transaction.findFirst({
    where: {
      userId,
      description: {
        equals: description.trim(),
        mode: "insensitive",
      },
      amount,
      date: {
        gte: dayStart,
        lte: dayEnd,
      },
      deletedAt: null,
    },
  })

  return duplicate
}

export async function filterDuplicates(
  userId: string,
  transactions: Array<{ description: string; amount: number; date: Date }>
): Promise<{ unique: typeof transactions; duplicateCount: number }> {
  const unique: typeof transactions = []
  let duplicateCount = 0

  for (const t of transactions) {
    const dup = await findDuplicate({
      userId,
      description: t.description,
      amount: t.amount,
      date: t.date,
    })
    if (dup) {
      duplicateCount++
    } else {
      unique.push(t)
    }
  }

  return { unique, duplicateCount }
}

